// Generates the grayscale Haikei-style SVG backgrounds into public/backgrounds/.
// Deterministic (seeded PRNG) so assets can be regenerated by re-running:
//   node scripts/gen-backgrounds.js public/backgrounds
const fs = require("fs");
const path = require("path");

const outDir = process.argv[2];
if (!outDir) throw new Error("usage: node gen-backgrounds.js <outDir>");
fs.mkdirSync(outDir, { recursive: true });

function mulberry32(seed) {
  return function () {
    seed |= 0;
    seed = (seed + 0x6d2b79f5) | 0;
    let t = Math.imul(seed ^ (seed >>> 15), 1 | seed);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// --- hero-lowpoly.svg: low-poly triangular grid, grayscale strokes ---
{
  const rnd = mulberry32(7);
  const W = 1440, H = 900, COLS = 16, ROWS = 10;
  const pts = [];
  for (let r = 0; r <= ROWS; r++) {
    const row = [];
    for (let c = 0; c <= COLS; c++) {
      const jx = c === 0 || c === COLS ? 0 : (rnd() - 0.5) * 60;
      const jy = r === 0 || r === ROWS ? 0 : (rnd() - 0.5) * 55;
      row.push([Math.round((c * W) / COLS + jx), Math.round((r * H) / ROWS + jy)]);
    }
    pts.push(row);
  }
  let tris = "";
  for (let r = 0; r < ROWS; r++) {
    for (let c = 0; c < COLS; c++) {
      const a = pts[r][c], b = pts[r][c + 1], d = pts[r + 1][c], e = pts[r + 1][c + 1];
      const shade = () => {
        const g = 120 + Math.floor(rnd() * 120);
        return `rgb(${g},${g},${g})`;
      };
      tris += `<polygon points="${a} ${b} ${d}" fill="none" stroke="${shade()}" stroke-width="1"/>`;
      tris += `<polygon points="${b} ${e} ${d}" fill="none" stroke="${shade()}" stroke-width="1"/>`;
    }
  }
  fs.writeFileSync(
    path.join(outDir, "hero-lowpoly.svg"),
    `<!-- Haikei-style low-poly grid | grayscale strokes | seed 7, 16x10 jittered grid | regen: scripts/gen-backgrounds.js -->
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${W} ${H}" preserveAspectRatio="xMidYMid slice">${tris}</svg>`
  );
}

// --- divider-waves.svg: layered waves section divider ---
{
  const W = 1440, H = 260;
  const layers = [
    { amp: 42, phase: 0.0, y: 110, fill: "#e5e5e5", op: 0.55 },
    { amp: 34, phase: 1.8, y: 150, fill: "#a3a3a3", op: 0.4 },
    { amp: 26, phase: 3.4, y: 190, fill: "#737373", op: 0.3 },
    { amp: 18, phase: 5.1, y: 225, fill: "#404040", op: 0.25 },
  ];
  const paths = layers
    .map((l) => {
      let d = `M0 ${l.y}`;
      for (let x = 0; x <= W; x += 24) {
        const y = l.y + Math.sin(x / 160 + l.phase) * l.amp;
        d += ` L${x} ${Math.round(y)}`;
      }
      d += ` L${W} ${H} L0 ${H} Z`;
      return `<path d="${d}" fill="${l.fill}" fill-opacity="${l.op}"/>`;
    })
    .join("");
  fs.writeFileSync(
    path.join(outDir, "divider-waves.svg"),
    `<!-- Haikei-style layered waves | grayscale | 4 sine layers | regen: scripts/gen-backgrounds.js -->
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${W} ${H}" preserveAspectRatio="none">${paths}</svg>`
  );
}

// --- empty-blobs.svg: blob scatter for empty states ---
{
  const rnd = mulberry32(21);
  const W = 800, H = 500;
  let blobs = "";
  for (let i = 0; i < 9; i++) {
    const cx = 60 + rnd() * (W - 120);
    const cy = 60 + rnd() * (H - 120);
    const r = 24 + rnd() * 70;
    const n = 8;
    let d = "";
    const first = [];
    for (let k = 0; k <= n; k++) {
      const ang = (k / n) * Math.PI * 2;
      const rr = r * (0.75 + rnd() * 0.5);
      const x = (cx + Math.cos(ang) * rr).toFixed(1);
      const y = (cy + Math.sin(ang) * rr).toFixed(1);
      if (k === 0) {
        d = `M${x} ${y}`;
        first.push(x, y);
      } else d += ` Q${cx.toFixed(1)} ${cy.toFixed(1)} ${x} ${y}`;
    }
    d += " Z";
    const g = 140 + Math.floor(rnd() * 90);
    blobs += `<path d="${d}" fill="rgb(${g},${g},${g})" fill-opacity="${(0.12 + rnd() * 0.14).toFixed(2)}"/>`;
  }
  fs.writeFileSync(
    path.join(outDir, "empty-blobs.svg"),
    `<!-- Haikei-style blob scatter | grayscale | seed 21, 9 blobs | regen: scripts/gen-backgrounds.js -->
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${W} ${H}" preserveAspectRatio="xMidYMid slice">${blobs}</svg>`
  );
}

// --- roadmap-circles.svg: circle scatter backdrop ---
{
  const rnd = mulberry32(42);
  const W = 800, H = 1200;
  let circles = "";
  for (let i = 0; i < 26; i++) {
    const cx = (rnd() * W).toFixed(0);
    const cy = (rnd() * H).toFixed(0);
    const r = (6 + rnd() * 56).toFixed(0);
    const g = 130 + Math.floor(rnd() * 110);
    const filled = rnd() > 0.6;
    circles += filled
      ? `<circle cx="${cx}" cy="${cy}" r="${r}" fill="rgb(${g},${g},${g})" fill-opacity="${(0.08 + rnd() * 0.1).toFixed(2)}"/>`
      : `<circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="rgb(${g},${g},${g})" stroke-opacity="${(0.18 + rnd() * 0.18).toFixed(2)}"/>`;
  }
  fs.writeFileSync(
    path.join(outDir, "roadmap-circles.svg"),
    `<!-- Haikei-style circle scatter | grayscale | seed 42, 26 circles | regen: scripts/gen-backgrounds.js -->
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${W} ${H}" preserveAspectRatio="xMidYMid slice">${circles}</svg>`
  );
}

console.log("wrote", fs.readdirSync(outDir).join(", "));
